import React, { useEffect, useRef } from 'react';



function GradientMesh({ size = 900, className = '' }) {

  const canvasRef = useRef(null);

  const animationRef = useRef(null);

  const timeRef = useRef(0);



  useEffect(() => {

    const canvas = canvasRef.current;

    const ctx = canvas.getContext('2d');

    const dpr = window.devicePixelRatio || 1;



    canvas.width = size * dpr;

    canvas.height = size * dpr;

    ctx.scale(dpr, dpr);



    // Nhiều blobs hơn, đa dạng size

    const blobs = [

      // Large background blobs

      { x: size * 0.25, y: size * 0.25, radius: size * 0.4, color: [139, 92, 246], speedX: 0.2, speedY: 0.15, opacity: 0.35 },

      { x: size * 0.75, y: size * 0.35, radius: size * 0.38, color: [59, 130, 246], speedX: -0.18, speedY: 0.22, opacity: 0.3 },

      { x: size * 0.5, y: size * 0.75, radius: size * 0.35, color: [80, 200, 255], speedX: 0.15, speedY: -0.2, opacity: 0.32 },



      // Medium accent blobs

      { x: size * 0.65, y: size * 0.25, radius: size * 0.22, color: [168, 85, 247], speedX: -0.25, speedY: -0.15, opacity: 0.4 },

      { x: size * 0.3, y: size * 0.6, radius: size * 0.2, color: [34, 211, 238], speedX: 0.28, speedY: 0.18, opacity: 0.35 },

      { x: size * 0.8, y: size * 0.7, radius: size * 0.18, color: [192, 132, 252], speedX: -0.22, speedY: 0.25, opacity: 0.38 },



      // Small highlight blobs

      { x: size * 0.4, y: size * 0.4, radius: size * 0.12, color: [255, 255, 255], speedX: 0.35, speedY: -0.3, opacity: 0.15 },

      { x: size * 0.6, y: size * 0.55, radius: size * 0.1, color: [124, 58, 237], speedX: -0.32, speedY: 0.28, opacity: 0.45 },

    ];



    // Particles

    const particles = Array.from({ length: 40 }, () => ({

      x: Math.random() * size,

      y: Math.random() * size,

      size: Math.random() * 2 + 1,

      speedX: (Math.random() - 0.5) * 0.3,

      speedY: (Math.random() - 0.5) * 0.3,

      opacity: Math.random() * 0.5 + 0.2,

    }));



    function draw() {

      ctx.clearRect(0, 0, size, size);



      const t = timeRef.current;



      // Draw blobs

      blobs.forEach((blob, i) => {

        const offsetX = Math.sin(t * blob.speedX + i * 1.5) * size * 0.1;

        const offsetY = Math.cos(t * blob.speedY + i * 2) * size * 0.1;

        const pulseScale = 1 + Math.sin(t * 0.4 + i * 0.7) * 0.15;



        const x = blob.x + offsetX;

        const y = blob.y + offsetY;

        const r = blob.radius * pulseScale;



        const gradient = ctx.createRadialGradient(x, y, 0, x, y, r);

        gradient.addColorStop(0, `rgba(${blob.color[0]}, ${blob.color[1]}, ${blob.color[2]}, ${blob.opacity})`);

        gradient.addColorStop(0.4, `rgba(${blob.color[0]}, ${blob.color[1]}, ${blob.color[2]}, ${blob.opacity * 0.5})`);

        gradient.addColorStop(1, `rgba(${blob.color[0]}, ${blob.color[1]}, ${blob.color[2]}, 0)`);



        ctx.fillStyle = gradient;

        ctx.beginPath();

        ctx.arc(x, y, r, 0, Math.PI * 2);

        ctx.fill();

      });



      // Draw subtle particles

      particles.forEach((p, i) => {

        p.x += p.speedX + Math.sin(t * 0.5 + i) * 0.1;

        p.y += p.speedY + Math.cos(t * 0.5 + i) * 0.1;



        // Wrap around

        if (p.x < 0) p.x = size;

        if (p.x > size) p.x = 0;

        if (p.y < 0) p.y = size;

        if (p.y > size) p.y = 0;



        const flicker = 0.5 + Math.sin(t * 2 + i * 3) * 0.5;



        ctx.beginPath();

        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);

        ctx.fillStyle = `rgba(200, 180, 255, ${p.opacity * flicker})`;

        ctx.fill();

      });



      // Overlay light streaks

      for (let i = 0; i < 3; i++) {

        const streakX = size * 0.3 + Math.sin(t * 0.3 + i * 2) * size * 0.3;

        const streakY = size * 0.2 + i * size * 0.25;

        const streakWidth = size * 0.5 + Math.sin(t * 0.2 + i) * size * 0.1;



        const streakGradient = ctx.createLinearGradient(streakX - streakWidth/2, streakY, streakX + streakWidth/2, streakY);

        streakGradient.addColorStop(0, 'rgba(139, 92, 246, 0)');

        streakGradient.addColorStop(0.5, `rgba(139, 92, 246, ${0.08 + Math.sin(t * 0.5 + i) * 0.04})`);

        streakGradient.addColorStop(1, 'rgba(139, 92, 246, 0)');



        ctx.fillStyle = streakGradient;

        ctx.fillRect(streakX - streakWidth/2, streakY - 30, streakWidth, 60);

      }



      timeRef.current += 0.008;

      animationRef.current = requestAnimationFrame(draw);

    }



    draw();



    return () => {

      if (animationRef.current) {

        cancelAnimationFrame(animationRef.current);

      }

    };

  }, [size]);



  return (

    <div className={`absolute pointer-events-none ${className}`} style={{

      filter: 'blur(50px)',

    }}>

      <canvas 

        ref={canvasRef}

        style={{ width: size, height: size }}

      />

    </div>

  );

}



export default GradientMesh;
